def seed_product_families(session: Session) -> None:
    for idx, item in enumerate(PRODUCT_FAMILY_SEED, start=1):
        row = session.exec(select(ProductFamily).where(ProductFamily.code == item["code"])).first()
        if not row:
            row = ProductFamily(code=item["code"])
        row.area = item["area"]
        row.label = item["label"]
        row.description = item["description"]
        row.sort_order = idx
        row.is_active = True
        row.updated_at = utcnow()
        session.add(row)
    session.commit()


def seed_internal_services(session: Session, company_id: int) -> None:
    for item in INTERNAL_SERVICE_SEED:
        _upsert_internal_service_compat(
            session,
            company_id=company_id,
            area=str(item["area"]).strip(),
            family=str(item["family_code"]).strip(),
            name=str(item["name"]).strip(),
            description=str(item["description"]).strip(),
            priority_weight=int(item["priority_weight"]),
            notes="",
            is_active=True,
        )
    session.commit()

def _json_dump_list(items: list[str]) -> str:
    return json.dumps([str(x).strip() for x in items if str(x).strip()], ensure_ascii=False)


def _json_list(s: str) -> list[str]:
    try:
        data = json.loads(s or "[]")
        return [str(x).strip() for x in data if str(x).strip()]
    except Exception:
        return []




def _table_columns_meta(session: Session, table_name: str) -> list[dict[str, Any]]:
    backend = engine.url.get_backend_name()
    if backend.startswith("postgres"):
        rows = session.execute(text("""
            SELECT column_name, data_type, is_nullable
            FROM information_schema.columns
            WHERE table_schema = current_schema()
              AND table_name = :table_name
            ORDER BY ordinal_position
        """), {"table_name": table_name}).fetchall()
        return [
            {"name": str(r[0]), "type": str(r[1] or "").lower(), "nullable": str(r[2] or "").upper() == "YES"}
            for r in rows
        ]
    rows = session.execute(text(f"PRAGMA table_info('{table_name}')")).fetchall()
    return [{"name": str(r[1]), "type": str(r[2] or "").lower(), "nullable": not bool(r[3])} for r in rows]


