def get_or_create_business_profile(session: Session, *, company_id: int, client_id: int) -> ClientBusinessProfile:
    row = session.exec(
        select(ClientBusinessProfile).where(
            ClientBusinessProfile.company_id == company_id,
            ClientBusinessProfile.client_id == client_id,
        )
    ).first()
    if row:
        if getattr(row, "banks_count", None) in (None, ""):
            row.banks_count = int(getattr(row, "banking_relationships_count", 0) or 0)
        if getattr(row, "banking_relationships_count", None) in (None, ""):
            row.banking_relationships_count = int(getattr(row, "banks_count", 0) or 0)
        return row

    _insert_or_ignore_business_profile_compat(session, company_id=company_id, client_id=client_id)

    row = session.exec(
        select(ClientBusinessProfile).where(
            ClientBusinessProfile.company_id == company_id,
            ClientBusinessProfile.client_id == client_id,
        )
    ).first()
    if row:
        if getattr(row, "banks_count", None) in (None, ""):
            row.banks_count = int(getattr(row, "banking_relationships_count", 0) or 0)
        if getattr(row, "banking_relationships_count", None) in (None, ""):
            row.banking_relationships_count = int(getattr(row, "banks_count", 0) or 0)
        return row

    row = ClientBusinessProfile(company_id=company_id, client_id=client_id, banks_count=0, banking_relationships_count=0)
    session.add(row)
    session.commit()
    session.refresh(row)
    return row



def _sync_business_profile_legacy_columns(session: Session, profile: ClientBusinessProfile) -> None:
    try:
        cols = {c["name"] for c in _table_columns_meta(session, "clientbusinessprofile")}
        if not cols or not profile.id:
            return
        sets = []
        params: dict[str, Any] = {"id": int(profile.id)}
        if "banking_relationships_count" in cols:
            sets.append("banking_relationships_count = :banking_relationships_count")
            params["banking_relationships_count"] = int(profile.banks_count or 0)
        if "monthly_payroll_brl" in cols:
            sets.append("monthly_payroll_brl = :monthly_payroll_brl")
            params["monthly_payroll_brl"] = float(profile.payroll_monthly_brl or 0.0)
        if "monthly_receivables_brl" in cols:
            sets.append("monthly_receivables_brl = :monthly_receivables_brl")
            params["monthly_receivables_brl"] = float(profile.receivables_brl or 0.0)
        if "collateral_available_brl" in cols:
            sets.append("collateral_available_brl = :collateral_available_brl")
            params["collateral_available_brl"] = float(profile.collateral_brl or 0.0)
        if "desired_credit_amount_brl" in cols:
            sets.append("desired_credit_amount_brl = :desired_credit_amount_brl")
            params["desired_credit_amount_brl"] = float(profile.desired_credit_brl or 0.0)
        if sets:
            session.execute(text(f"UPDATE clientbusinessprofile SET {', '.join(sets)} WHERE id = :id"), params)
            session.commit()
    except Exception:
        try:
            session.rollback()
        except Exception:
            pass

def list_product_families(session: Session, area: str = "") -> list[ProductFamily]:
    q = select(ProductFamily).where(ProductFamily.is_active == True)
    if area:
        q = q.where(ProductFamily.area == area)
    return session.exec(q.order_by(ProductFamily.sort_order.asc(), ProductFamily.label.asc())).all()


def compute_offer_engine(*, session: Session, company_id: int, client: Client, profile: ClientBusinessProfile, latest_snapshot: Optional[ClientSnapshot]) -> list[dict[str, Any]]:
    score_total_snap = float(latest_snapshot.score_total) if latest_snapshot else 0.0
    score_fin_snap = float(latest_snapshot.score_financial) if latest_snapshot else 0.0
    score_proc_snap = float(latest_snapshot.score_process) if latest_snapshot else 0.0
    revenue_monthly = max(float(client.revenue_monthly_brl or 0.0), float(profile.annual_revenue_brl or 0.0) / 12.0)
    debt_total = max(float(client.debt_total_brl or 0.0), 0.0)
    cash_balance = float(client.cash_balance_brl or 0.0)
    debt_ratio = debt_total / max(revenue_monthly, 1.0)
    txt = " ".join([profile.strategic_goal or "", profile.pain_points or "", " ".join(_json_list(profile.interests_json)), latest_snapshot.notes if latest_snapshot else ""]).lower()

    scores = {item["code"]: 0.0 for item in PRODUCT_FAMILY_SEED}
    if revenue_monthly > 0:
        scores["capital_giro"] += 28
        if cash_balance < revenue_monthly * 0.5:
            scores["capital_giro"] += 12
        if profile.receivables_brl > 0:
            scores["antecipacao_recebiveis"] += 22
        if profile.collateral_brl > 0:
            scores["home_equity"] += 24
            scores["auto_equity"] += 10
        if "cart" in txt:
            scores["antecipacao_cartoes"] += 18
        if "consorcio" in txt:
            scores["consorcio"] += 16
        if "cambio" in txt:
            scores["cambio"] += 18
        if "import" in txt or "export" in txt or "comercio exterior" in txt:
            scores["trade_finance"] += 22
        if "veicul" in txt or "frota" in txt:
            scores["financiamento_veiculos"] += 16
        scores["analise_credito"] += 12

    if score_total_snap < 65 or score_proc_snap < 60:
        scores["turnaround"] += 30
        scores["estrategia_financeira"] += 22
    if "valuation" in txt or "valor da empresa" in txt:
        scores["valuation"] += 30
    if "equity" in txt or "investidor" in txt or "captacao" in txt:
        scores["rodada_seed"] += 26
        scores["equity_roadshow"] += 22
    if revenue_monthly >= 300000:
        scores["debenture"] += 16
        scores["cri_cra"] += 14
    if "vender empresa" in txt:
        scores["ma_sell_side"] += 24
    if "comprar empresa" in txt or "aquisicao" in txt:
        scores["ma_buy_side"] += 18
    if "rj" in txt or "recuperacao judicial" in txt:
        scores["plano_rj"] += 35
        scores["credito_rj"] += 34
        scores["dip_financing"] += 24
    if "tributario" in txt or "precatorio" in txt:
        scores["credito_tributario"] += 30
    if "distress" in txt or "estressad" in txt:
        scores["distressed_ma"] += 24

    for interest in _json_list(profile.interests_json):
        if interest in scores:
            scores[interest] += 24

    services = session.exec(select(InternalService).where(InternalService.company_id == company_id, InternalService.is_active == True).order_by(InternalService.priority_weight.desc())).all()
    partner_products = session.exec(select(PartnerProduct).where(PartnerProduct.company_id == company_id, PartnerProduct.is_active == True).order_by(PartnerProduct.name.asc())).all()
    families = {f.code: f for f in list_product_families(session)}
    partners = {pp.id: session.get(Partner, pp.partner_id) for pp in partner_products}

    def eligible(pp: PartnerProduct) -> bool:
        desired = float(profile.desired_credit_brl or 0.0)
        if pp.revenue_min_brl and revenue_monthly < pp.revenue_min_brl:
            return False
        if pp.revenue_max_brl and revenue_monthly > pp.revenue_max_brl > 0:
            return False
        if desired and pp.ticket_min_brl and desired < pp.ticket_min_brl:
            return False
        if desired and pp.ticket_max_brl and desired > pp.ticket_max_brl > 0:
            return False
        if pp.score_total_min and score_total_snap < pp.score_total_min:
            return False
        if pp.score_financial_min and score_fin_snap < pp.score_financial_min:
            return False
        if pp.max_debt_ratio and debt_ratio > pp.max_debt_ratio:
            return False
        if pp.requires_collateral and float(profile.collateral_brl or 0.0) <= 0:
            return False
        states = _json_list(pp.allowed_states_json)
        if states and (client.state or "").upper() not in {s.upper() for s in states}:
            return False
        segs = _json_list(pp.allowed_segments_json)
        if segs and (profile.segment or "").lower() not in {s.lower() for s in segs}:
            return False
        return True

    out = []
    for svc in services:
        base = scores.get(svc.family_code, 0.0)
        if base <= 0:
            continue
        svc_family = (svc.family_code or getattr(svc, 'family_slug', '') or '').strip()
        elig = [pp for pp in partner_products if ((pp.family_code or getattr(pp, 'family_slug', '') or '').strip() == svc_family) and eligible(pp)]
        score_fit = round(min(100.0, base + max(0, svc.priority_weight - 50) * 0.4 + min(len(elig) * 2, 8)), 2)
        priority = "alta" if score_fit >= 75 else "media" if score_fit >= 55 else "baixa"
        fam = families.get(svc_family or svc.family_code)
        out.append({"source_kind":"internal","family_code":svc_family or svc.family_code,"area":svc.area,"product_name":svc.name,"partner_name":"","priority_level":priority,"score_fit":score_fit,"reason_summary":f"Solucao interna recomendada. Parceiros elegiveis nesta familia: {len(elig)}.","partner_options_count":len(elig),"internal_service_id":svc.id,"partner_product_id":None,"family_label":fam.label if fam else (svc_family or svc.family_code)})
        for pp in elig:
            partner = partners.get(pp.id)
            out.append({"source_kind":"partner","family_code":svc_family or svc.family_code,"area":svc.area,"product_name":pp.name,"partner_name":partner.name if partner else "Parceiro","priority_level":priority,"score_fit":min(100.0, score_fit + 4),"reason_summary":f"Parceiro elegivel para a familia {fam.label if fam else (svc_family or svc.family_code)}.","partner_options_count":len(elig),"internal_service_id":svc.id,"partner_product_id":pp.id,"family_label":fam.label if fam else (svc_family or svc.family_code)})

    out.sort(key=lambda x: (0 if x["priority_level"] == "alta" else 1 if x["priority_level"] == "media" else 2, -float(x["score_fit"])))
    return out



def _insert_offer_match_compat(
    session: Session,
    *,
    company_id: int,
    client_id: int,
    subject_doc: str,
    item: dict[str, Any],
) -> None:
    cols_meta = _table_columns_meta(session, "offermatch")
    if not cols_meta:
        session.add(OfferMatch(
            company_id=company_id,
            client_id=client_id,
            family_code=item.get("family_code") or "",
            source_kind=item.get("source_kind") or "internal",
            internal_service_id=item.get("internal_service_id"),
            partner_product_id=item.get("partner_product_id"),
            area=item.get("area") or "",
            product_name=item.get("product_name") or "",
            partner_name=item.get("partner_name") or "",
            priority_level=item.get("priority_level") or "media",
            score_fit=float(item.get("score_fit") or 0.0),
            reason_summary=item.get("reason_summary") or "",
            partner_options_count=int(item.get("partner_options_count") or 0),
        ))
        return

    provided: dict[str, Any] = {
        "company_id": company_id,
        "client_id": client_id,
        "subject_doc": subject_doc or "",
        "family_code": item.get("family_code") or "",
        "source_kind": item.get("source_kind") or "internal",
        "internal_service_id": item.get("internal_service_id"),
        "partner_product_id": item.get("partner_product_id"),
        "area": item.get("area") or "",
        "product_name": item.get("product_name") or "",
        "partner_name": item.get("partner_name") or "",
        "priority_level": item.get("priority_level") or "media",
        "score_fit": float(item.get("score_fit") or 0.0),
        "reason_summary": item.get("reason_summary") or "",
        "estimated_commission_text": item.get("estimated_commission_text") or "",
        "partner_options_count": int(item.get("partner_options_count") or 0),
        "created_at": item.get("created_at") or utcnow(),
    }

    names: list[str] = []
    params: dict[str, Any] = {}
    for meta in cols_meta:
        col = meta["name"]
        if col == "id":
            continue
        if col in provided:
            val = provided[col]
        elif not meta["nullable"]:
            val = _generic_sql_default_for_column(col, meta["type"])
        else:
            continue
        names.append(col)
        params[col] = val

    if not names:
        return

    cols_sql = ", ".join(names)
    placeholders = ", ".join(f":{c}" for c in names)
    sql = f"INSERT INTO offermatch ({cols_sql}) VALUES ({placeholders})"
    session.execute(text(sql), params)



def persist_offer_matches(session: Session, *, company_id: int, client_id: int, matches: list[dict[str, Any]]) -> None:
    old = session.exec(
        select(OfferMatch).where(
            OfferMatch.company_id == company_id,
            OfferMatch.client_id == client_id,
        )
    ).all()

    old_ids = [int(row.id) for row in old if row.id]

    if old_ids:
        reviews = session.exec(
            select(OfferVisibilityReview).where(
                OfferVisibilityReview.offer_match_id.in_(old_ids)
            )
        ).all()
        for review in reviews:
            session.delete(review)

    for row in old:
        session.delete(row)

    session.commit()

    client = session.get(Client, client_id)
    subject_doc = _digits(getattr(client, "cnpj", "") or "") if client else ""
    if not subject_doc and client:
        subject_doc = _digits(getattr(client, "email", "") or "") or ""

    for item in matches:
        _insert_offer_match_compat(
            session,
            company_id=company_id,
            client_id=client_id,
            subject_doc=subject_doc,
            item=item,
        )

    session.commit()

    try:
        sync_offer_reviews(session, company_id=company_id, client_id=client_id)
    except Exception:
        session.rollback()

