def _extract_first_url(text: str) -> str:
    if not text:
        return ""
    m = re.search(r"(https?://\S+)", text)
    return (m.group(1).rstrip(").,;") if m else "")


def _deep_iter_values(value: Any):
    if isinstance(value, dict):
        for v in value.values():
            yield from _deep_iter_values(v)
    elif isinstance(value, list):
        for item in value:
            yield from _deep_iter_values(item)
    else:
        yield value


def _deep_find_urls(value: Any) -> list[str]:
    urls: list[str] = []
    for raw in _deep_iter_values(value):
        if raw is None:
            continue
        text_value = str(raw).strip()
        if not text_value:
            continue
        for m in re.finditer(r"(https?://\S+)", text_value):
            url = m.group(1).rstrip(").,;")
            if url and url not in urls:
                urls.append(url)
    return urls


def _extract_boleto_url_from_receivable_payload(det: dict[str, Any]) -> str:
    # 1) tenta campos explícitos mais comuns
    explicit_candidates = [
        det.get("url_pagamento"),
        det.get("payment_url"),
        det.get("link_pagamento"),
        det.get("link_boleto"),
        det.get("boleto_url"),
    ]
    fatura = det.get("fatura")
    if isinstance(fatura, dict):
        explicit_candidates.extend(
            [
                fatura.get("url_pagamento"),
                fatura.get("payment_url"),
                fatura.get("link_pagamento"),
                fatura.get("link_boleto"),
                fatura.get("boleto_url"),
            ]
        )
    for candidate in explicit_candidates:
        url = _extract_first_url(str(candidate or ""))
        if url:
            return url

    # 2) tenta nas solicitações de cobrança, priorizando a mais recente
    solicitacoes = det.get("solicitacoes_cobrancas") or []
    if isinstance(solicitacoes, list):
        for raw_last in reversed(solicitacoes):
            last = raw_last if isinstance(raw_last, dict) else {}
            notif = last.get("notificacao_cobranca") or {}
            body = str(notif.get("corpo") or "")
            url = _extract_first_url(body)
            if url:
                return url

            for candidate in _deep_find_urls(last):
                if candidate:
                    return candidate

    # 3) fallback: procura qualquer URL no payload inteiro
    for candidate in _deep_find_urls(det):
        if candidate:
            return candidate

    return ""


def _extract_nfse_real_document_url(payload: dict[str, Any]) -> str:
    if not isinstance(payload, dict):
        return ""

    # prioriza chaves/links típicos de NFS-e real / prefeitura / DANFSE
    preferred_keys = {
        "link_prefeitura",
        "url_prefeitura",
        "danfse",
        "danfse_url",
        "url_danfse",
        "pdf",
        "pdf_url",
        "url_pdf",
        "link_pdf",
        "arquivo_pdf",
        "download_pdf",
        "link_nota_fiscal",
        "url_nota_fiscal",
        "espelho_nota",
        "url_espelho_nota",
    }

    def walk(obj: Any):
        if isinstance(obj, dict):
            for key, value in obj.items():
                key_norm = str(key or "").strip().lower()
                if key_norm in preferred_keys:
                    url = _extract_first_url(str(value or ""))
                    if url:
                        return url
                result = walk(value)
                if result:
                    return result
        elif isinstance(obj, list):
            for item in obj:
                result = walk(item)
                if result:
                    return result
        else:
            text_value = str(obj or "").strip()
            if text_value.startswith("http://") or text_value.startswith("https://"):
                lowered = text_value.lower()
                if any(
                    token in lowered
                    for token in ["prefeitura", "nfse", "danfse", "nota", "pdf", "govbr", "issdigital"]
                ):
                    return text_value
        return ""

    return walk(payload) or ""


def _nfse_norm_key(value: Any) -> str:
    import unicodedata
    s = unicodedata.normalize("NFKD", str(value or ""))
    s = "".join(ch for ch in s if not unicodedata.combining(ch))
    s = s.lower().strip()
    s = re.sub(r"[^a-z0-9]+", "", s)
    return s


def _walk_nfse_scalars(obj: Any, path: Optional[list[str]] = None) -> list[tuple[list[str], str]]:
    path = list(path or [])
    items: list[tuple[list[str], str]] = []

    if isinstance(obj, dict):
        for key, value in obj.items():
            key_norm = _nfse_norm_key(key)
            items.extend(_walk_nfse_scalars(value, path + [key_norm]))
        return items

    if isinstance(obj, list):
        for idx, value in enumerate(obj):
            items.extend(_walk_nfse_scalars(value, path + [str(idx)]))
        return items

    if obj is None:
        return items

    s = str(obj).strip()
    if s:
        items.append((path, s))
    return items


def _extract_nfse_payload_value(payload: Any, wanted_keys: set[str]) -> str:
    if not wanted_keys:
        return ""

    wanted = {_nfse_norm_key(x) for x in wanted_keys if str(x or "").strip()}
    if not wanted:
        return ""

    for path, value in _walk_nfse_scalars(payload):
        if path and path[-1] in wanted and str(value).strip():
            return str(value).strip()
    return ""


def _extract_nfse_public_fields(payload: dict[str, Any]) -> dict[str, str]:
    if not isinstance(payload, dict):
        return {}

    flat = _walk_nfse_scalars(payload)
    fields: dict[str, str] = {}

    def path_has(path: list[str], tokens: set[str]) -> bool:
        return any(tok in tokens for tok in path)

    def first(
        *,
        exact_keys: Optional[set[str]] = None,
        bare_keys: Optional[set[str]] = None,
        contexts: Optional[set[str]] = None,
    ) -> str:
        exact_keys_norm = {_nfse_norm_key(x) for x in (exact_keys or set()) if str(x or "").strip()}
        bare_keys_norm = {_nfse_norm_key(x) for x in (bare_keys or set()) if str(x or "").strip()}
        contexts_norm = {_nfse_norm_key(x) for x in (contexts or set()) if str(x or "").strip()}

        for path, value in flat:
            if not path or not str(value).strip():
                continue
            last = path[-1]
            if exact_keys_norm and last in exact_keys_norm:
                return str(value).strip()
            if bare_keys_norm and last in bare_keys_norm:
                if not contexts_norm or path_has(path[:-1], contexts_norm):
                    return str(value).strip()
        return ""

    def first_regex(pattern: str, *, contexts: Optional[set[str]] = None) -> str:
        rx = re.compile(pattern, re.IGNORECASE)
        contexts_norm = {_nfse_norm_key(x) for x in (contexts or set()) if str(x or "").strip()}
        for path, value in flat:
            if contexts_norm and not path_has(path, contexts_norm):
                continue
            m = rx.search(str(value))
            if m:
                return m.group(1) if m.groups() else m.group(0)
        return ""

    numero_nfse = first(
        exact_keys={"numero_nfse", "numeroNfse", "numeroNota", "numero_nota"},
        bare_keys={"numero"},
        contexts={"nfse", "notafiscal", "notafiscalservico", "notaservico", "nfservico"},
    )
    numero_dps = first(
        exact_keys={"numero_dps", "numeroRps", "numero_rps", "dps_numero", "rps_numero"},
        bare_keys={"numero"},
        contexts={"dps", "rps"},
    )
    serie_dps = first(
        exact_keys={"serie_dps", "serieRps", "serie_rps", "rps_serie", "dps_serie"},
        bare_keys={"serie"},
        contexts={"dps", "rps"},
    )
    codigo = first(
        exact_keys={"codigo_verificacao", "codigoVerificacao", "verification_code", "codigoautenticidade"},
        bare_keys={"codigo"},
        contexts={"verificacao", "autenticidade"},
    )
    chave = first(
        exact_keys={"chave_acesso", "chaveAcesso", "access_key", "chave_nfse", "chavenfse"},
        bare_keys={"chave"},
        contexts={"acesso", "nfse", "notafiscal"},
    )
    cnpj = first(
        exact_keys={
            "cnpj_prestador", "cpf_cnpj_prestador", "cpfcnpjprestador", "documento_prestador",
            "cnpj_emitente", "cpf_cnpj_emitente", "cpfcnpjemitente",
        },
        bare_keys={"cnpj", "cpfcnpj", "documento"},
        contexts={"prestador", "emitente"},
    )

    if not cnpj:
        cnpj = first_regex(r'(\d{2}\.?\d{3}\.?\d{3}/?\d{4}-?\d{2})', contexts={"prestador", "emitente"})
    if not chave:
        chave = first_regex(r'(\d{20,60})', contexts={"chave", "acesso", "nfse"})
    if not codigo:
        codigo = first_regex(r'([A-Z0-9]{6,})', contexts={"verificacao", "autenticidade"})

    chave_digits = _digits_only(chave)
    if not cnpj and len(chave_digits) >= 23:
        candidate = chave_digits[9:23]
        if len(candidate) == 14:
            cnpj = candidate

    fields["numero_nfse"] = str(numero_nfse or payload.get("numero_nfse") or payload.get("numero") or "").strip()
    fields["numero_dps"] = str(numero_dps or payload.get("numero_dps") or payload.get("numero_rps") or "").strip()
    fields["serie_dps"] = str(serie_dps or payload.get("serie_dps") or payload.get("serie_rps") or "").strip()
    fields["codigo_verificacao"] = str(codigo or payload.get("codigo_verificacao") or "").strip()
    fields["chave_acesso"] = str(chave or payload.get("chave_acesso") or payload.get("chave") or "").strip()
    fields["cnpj_prestador"] = _digits_only(cnpj)
    fields["municipio"] = first(
        exact_keys={"municipio_prestacao", "municipio_emissao", "municipio"},
        bare_keys={"municipio"},
        contexts={"prestador", "enderecoprestador"},
    )
    fields["external_id"] = str(payload.get("id") or "").strip()

    return {k: v for k, v in fields.items() if v}


def _format_nfse_lookup_date(value: Any) -> str:
    s = str(value or "").strip()
    if not s:
        return "—"
    m = re.match(r"^(\d{4})-(\d{2})-(\d{2})", s)
    if m:
        return f"{m.group(3)}/{m.group(2)}/{m.group(1)}"
    return s


def _build_nfse_public_document_url(payload: dict[str, Any]) -> str:
    direct = _extract_nfse_real_document_url(payload)
    if direct:
        return direct

    fields = _extract_nfse_public_fields(payload)
    chave = str(fields.get("chave_acesso") or "").strip()
    if chave:
        from urllib.parse import quote
        return NACIONAL_NFSE_DANFSE_URL.format(chave=quote(chave, safe=""))

    return ""


def _render_nfse_lookup_page(*, inv: "ContaAzulInvoice", payload: dict[str, Any]) -> str:
    fields = _extract_nfse_public_fields(payload)
    numero = html.escape(str(fields.get("numero_nfse") or inv.number or "—"))
    codigo = html.escape(str(fields.get("codigo_verificacao") or "—"))
    chave = html.escape(str(fields.get("chave_acesso") or "—"))
    dps_num = html.escape(str(fields.get("numero_dps") or "—"))
    dps_serie = html.escape(str(fields.get("serie_dps") or "—"))
    cnpj = html.escape(str(fields.get("cnpj_prestador") or "—"))
    issue_date = html.escape(_format_nfse_lookup_date(getattr(inv, "issue_date", "") or payload.get("data_competencia") or payload.get("data_emissao") or "—"))
    external_id = html.escape(str(getattr(inv, "external_id", "") or "—"))
    brusque_url = html.escape(BRUSQUE_NFSE_AUTH_URL)
    nacional_url = html.escape(NACIONAL_NFSE_CONSULTA_URL)

    missing = []
    for label, value in [
        ("código de verificação", codigo),
        ("chave de acesso", chave),
        ("série DPS/RPS", dps_serie),
        ("CNPJ do prestador", cnpj),
    ]:
        if value == "—":
            missing.append(label)
    missing_note = ""
    if missing:
        missing_note = f'<div class="note subtle">A integração não trouxe automaticamente: {html.escape(", ".join(missing))}. Os demais dados já ajudam na busca manual.</div>'

    return f"""<!doctype html>
<html lang="pt-BR">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>NFS-e oficial indisponível</title>
  <style>
    body {{ font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; margin: 0; background: #f6f7fb; color: #111827; }}
    .wrap {{ max-width: 820px; margin: 40px auto; padding: 0 20px; }}
    .card {{ background: #fff; border: 1px solid #e5e7eb; border-radius: 16px; padding: 24px; box-shadow: 0 8px 20px rgba(0,0,0,.04); }}
    h1 {{ font-size: 24px; margin: 0 0 8px; }}
    p {{ line-height: 1.5; }}
    .muted {{ color: #6b7280; }}
    .grid {{ display: grid; grid-template-columns: 220px 1fr; gap: 10px 14px; margin: 18px 0 22px; }}
    .k {{ color: #374151; font-weight: 600; }}
    .v {{ font-family: ui-monospace, SFMono-Regular, Menlo, monospace; word-break: break-all; }}
    .actions {{ display: flex; gap: 12px; flex-wrap: wrap; margin-top: 18px; }}
    .btn {{ display: inline-block; padding: 10px 14px; border-radius: 10px; text-decoration: none; border: 1px solid #d1d5db; }}
    .btn-primary {{ background: #111827; color: #fff; border-color: #111827; }}
    .btn-light {{ background: #fff; color: #111827; }}
    .note {{ background: #fff7ed; border: 1px solid #fed7aa; color: #9a3412; padding: 12px 14px; border-radius: 12px; margin-top: 16px; }}
    .note.subtle {{ background: #eff6ff; border-color: #bfdbfe; color: #1d4ed8; }}
  </style>
</head>
<body>
  <div class="wrap">
    <div class="card">
      <h1>NFS-e oficial não veio com link direto na integração</h1>
      <p class="muted">A Conta Azul sincronizou a nota, mas não entregou um link direto do PDF oficial. Use os dados abaixo para consultar a NFS-e na prefeitura de Brusque ou no portal nacional.</p>

      <div class="grid">
        <div class="k">Número da NFS-e</div><div class="v">{numero}</div>
        <div class="k">Data de emissão</div><div class="v">{issue_date}</div>
        <div class="k">Código de verificação</div><div class="v">{codigo}</div>
        <div class="k">Chave de acesso</div><div class="v">{chave}</div>
        <div class="k">Número DPS / RPS</div><div class="v">{dps_num}</div>
        <div class="k">Série DPS / RPS</div><div class="v">{dps_serie}</div>
        <div class="k">CNPJ do prestador</div><div class="v">{cnpj}</div>
        <div class="k">ID externo da integração</div><div class="v">{external_id}</div>
      </div>

      <div class="actions">
        <a class="btn btn-primary" href="{brusque_url}" target="_blank" rel="noopener">Consultar na Prefeitura de Brusque</a>
        <a class="btn btn-light" href="{nacional_url}" target="_blank" rel="noopener">Consultar no portal nacional</a>
      </div>

      <div class="note">
        Dica: se a prefeitura ou o portal nacional pedir número, código de verificação, DPS/RPS, série ou CNPJ do prestador, eles já estão listados acima.
      </div>
      {missing_note}
    </div>
  </div>
</body>
</html>"""


def _extract_sale_id_from_nfse_payload(payload: dict[str, Any]) -> str:
    if not isinstance(payload, dict):
        return ""
    candidates = [
        payload.get("id_venda"),
        payload.get("sale_id"),
        payload.get("venda_id"),
        payload.get("id"),
    ]
    venda = payload.get("venda")
    if isinstance(venda, dict):
        candidates.extend(
            [
                venda.get("id"),
                venda.get("id_venda"),
                venda.get("sale_id"),
                venda.get("venda_id"),
            ]
        )

    for candidate in candidates:
        text_value = str(candidate or "").strip()
        if text_value:
            return text_value
    return ""


def _contaazul_get_auth(session: Session, company_id: int) -> Optional[ContaAzulAuth]:
    return session.exec(select(ContaAzulAuth).where(ContaAzulAuth.company_id == company_id)).first()


def _contaazul_save_auth(session: Session, auth: ContaAzulAuth) -> None:
    auth.updated_at = utcnow()
    session.add(auth)
    session.commit()


def _contaazul_refresh(session: Session, auth: ContaAzulAuth) -> ContaAzulAuth:
    headers = {
        "Authorization": f"Basic {_contaazul_basic_auth_value()}",
        "Content-Type": "application/x-www-form-urlencoded",
    }
    data = {"grant_type": "refresh_token", "refresh_token": auth.refresh_token}
    with httpx.Client(timeout=30.0, follow_redirects=True) as client:
        resp = client.post(CONTA_AZUL_TOKEN_URL, headers=headers, data=data)
    if resp.status_code >= 400:
        raise RuntimeError(f"Conta Azul refresh failed: HTTP {resp.status_code} {resp.text[:400]}")
    payload = resp.json()
    auth.access_token = str(payload.get("access_token") or "")
    auth.refresh_token = str(payload.get("refresh_token") or auth.refresh_token)
    auth.token_type = str(payload.get("token_type") or "Bearer")
    exp = int(payload.get("expires_in") or 3600)
    auth.expires_at = utcnow() + timedelta(seconds=max(60, exp))
    _contaazul_save_auth(session, auth)
    return auth


def _contaazul_bearer_headers(session: Session, company_id: int) -> dict[str, str]:
    auth = _contaazul_get_auth(session, company_id)
    if not auth or not auth.access_token or not auth.refresh_token:
        raise RuntimeError("Conta Azul não conectada.")

    exp_at = _as_aware_utc(auth.expires_at) or utcnow()
    if utcnow() >= (exp_at - timedelta(seconds=60)):
        auth = _contaazul_refresh(session, auth)
    return {"Authorization": f"Bearer {auth.access_token}"}


def _contaazul_get_json(session: Session, company_id: int, path: str, params: Any = None) -> Any:
    base = CONTA_AZUL_API_BASE.rstrip("/")
    url = base + path
    headers = _contaazul_bearer_headers(session, company_id)
    with httpx.Client(timeout=30.0, follow_redirects=True) as client:
        resp = client.get(url, headers=headers, params=params)
        if resp.status_code == 401:
            auth = _contaazul_get_auth(session, company_id)
            if auth:
                _contaazul_refresh(session, auth)
            headers = _contaazul_bearer_headers(session, company_id)
            resp = client.get(url, headers=headers, params=params)
    if resp.status_code >= 400:
        raise RuntimeError(f"Conta Azul API error: GET {path} HTTP {resp.status_code} {resp.text[:400]}")
    return resp.json()


def _contaazul_get_mapped_person_id(session: Session, *, company_id: int, client_id: int) -> str:
    pm = session.exec(
        select(ContaAzulPersonMap).where(
            ContaAzulPersonMap.company_id == company_id, ContaAzulPersonMap.client_id == client_id
        )
    ).first()
    return str((pm.contaazul_person_id or "") if pm else "").strip()


def _contaazul_find_person_id(session: Session, *, company_id: int, client: Client) -> str:
    doc = _digits_only(client.cnpj)
    if doc:
        payload = _contaazul_get_json(
            session,
            company_id,
            "/v1/pessoas",
            params={"documentos": doc, "tamanho_pagina": 10, "pagina": 1, "tipo_perfil": "Cliente"},
        )
        items = (payload.get("items") or []) if isinstance(payload, dict) else []
        if items:
            return str(items[0].get("id") or "")
    email = (client.finance_email or client.email or "").strip()
    if email:
        payload = _contaazul_get_json(
            session,
            company_id,
            "/v1/pessoas",
            params={"emails": email, "tamanho_pagina": 10, "pagina": 1, "tipo_perfil": "Cliente"},
        )
        items = (payload.get("items") or []) if isinstance(payload, dict) else []
        if items:
            return str(items[0].get("id") or "")
    return ""


def _contaazul_upsert_person_map(session: Session, *, company_id: int, client: Client, person_id: str) -> None:
    pm = session.exec(
        select(ContaAzulPersonMap).where(
            ContaAzulPersonMap.company_id == company_id, ContaAzulPersonMap.client_id == client.id
        )
    ).first()
    if not pm:
        pm = ContaAzulPersonMap(company_id=company_id, client_id=client.id, contaazul_person_id=person_id)
    pm.contaazul_person_id = person_id
    pm.documento = _digits_only(client.cnpj)
    pm.email = (client.finance_email or client.email or "").strip()
    pm.updated_at = utcnow()
    session.add(pm)
    session.commit()


def contaazul_sync_client_job(company_id: int, client_id: int) -> None:
    """Sincroniza boletos/receitas e notas do Conta Azul para o Financeiro do cliente.

    Observação importante: o mapeamento do "cliente" no Conta Azul (Pessoa) pode falhar se o
    documento/e-mail estiver diferente. Neste caso, fazemos fallback por documento (quando possível)
    para NFS-e e registramos logs (quando CONTA_AZUL_DEBUG=1)."""

    if not _contaazul_configured():
        return

    with Session(engine) as session:
        if not ensure_contaazul_tables():
            _ca_log("tables missing; abort")
            return

        auth = _contaazul_get_auth(session, company_id)
        if not auth or not auth.refresh_token:
            _ca_log("not connected; abort")
            return

        client = session.get(Client, client_id)
        if not client or client.company_id != company_id:
            _ca_log(f"client not found or not in company: client_id={client_id}")
            return

        doc = _digits_only(client.cnpj)
        email = (client.finance_email or client.email or "").strip()

        person_id = (
                _contaazul_get_mapped_person_id(session, company_id=company_id, client_id=client.id)
                or _contaazul_find_person_id(session, company_id=company_id, client=client)
        )
        if not person_id:
            _ca_log(f"person not found for client_id={client_id} doc={doc or '—'} email={email or '—'}")
        else:
            _contaazul_upsert_person_map(session, company_id=company_id, client=client, person_id=person_id)

        today = utcnow().date()
        start_venc = today - timedelta(days=max(1, int(CONTA_AZUL_SYNC_DAYS_BACK)))
        end_venc = today + timedelta(days=max(0, int(CONTA_AZUL_SYNC_DAYS_FORWARD)))

        # ----------------------------
        # Contas a receber / Parcelas
        # ----------------------------
        if person_id:
            installment_ids: list[str] = []
            page = 1
            page_size = 100
            while len(installment_ids) < CONTA_AZUL_SYNC_MAX_ITEMS:
                params = [
                    ("pagina", page),
                    ("tamanho_pagina", page_size),
                    ("data_vencimento_de", start_venc.isoformat()),
                    ("data_vencimento_ate", end_venc.isoformat()),
                    ("ids_clientes", person_id),
                ]
                try:
                    payload = _contaazul_get_json(
                        session,
                        company_id,
                        "/v1/financeiro/eventos-financeiros/contas-a-receber/buscar",
                        params=params,
                    )
                except Exception as e:
                    _ca_log(f"receivables search failed: {e}")
                    break

                itens = (payload.get("itens") or []) if isinstance(payload, dict) else []
                if not itens:
                    break

                for it in itens:
                    iid = str((it or {}).get("id") or "").strip()
                    if iid:
                        installment_ids.append(iid)
                    if len(installment_ids) >= CONTA_AZUL_SYNC_MAX_ITEMS:
                        break
                page += 1

            _ca_log(f"receivables: found {len(installment_ids)} parcelas for person_id={person_id}")

            for iid in installment_ids:
                try:
                    det = _contaazul_get_json(session, company_id, f"/v1/financeiro/eventos-financeiros/parcelas/{iid}")
                except Exception as e:
                    _ca_log(f"failed installment {iid}: {e}")
                    continue

                if not isinstance(det, dict):
                    continue

                fatura = det.get("fatura") or {}
                invoice_type = str(fatura.get("tipo_fatura") or "")
                invoice_number = str(fatura.get("numero") or "")

                boleto_status = ""
                payment_url = ""
                solicitacoes = det.get("solicitacoes_cobrancas") or []
                if isinstance(solicitacoes, list) and solicitacoes:
                    last = solicitacoes[-1] if isinstance(solicitacoes[-1], dict) else {}
                    boleto_status = str(last.get("status_solicitacao_cobranca") or "")
                payment_url = _extract_boleto_url_from_receivable_payload(det)

                rec = session.exec(
                    select(ContaAzulReceivable).where(
                        ContaAzulReceivable.company_id == company_id, ContaAzulReceivable.installment_id == iid
                    )
                ).first()
                if not rec:
                    rec = ContaAzulReceivable(company_id=company_id, client_id=client_id, installment_id=iid)

                rec.client_id = client_id
                rec.description = str(det.get("descricao") or "")
                rec.due_date = str(det.get("data_vencimento") or "")
                rec.status = str(det.get("status") or "")
                rec.amount_total = float(det.get("valor_total_liquido") or 0.0)
                rec.amount_open = float(det.get("nao_pago") or 0.0)
                rec.amount_paid = float(det.get("valor_pago") or 0.0)
                rec.payment_method = str(det.get("metodo_pagamento") or "")
                rec.invoice_type = invoice_type
                rec.invoice_number = invoice_number
                rec.boleto_status = boleto_status
                rec.payment_url = payment_url
                rec.raw_json = json.dumps(det, ensure_ascii=False)
                rec.updated_at = utcnow()
                session.add(rec)
                session.commit()

        # ----------------------------
        # Notas fiscais de serviço (NFS-e)
        # ----------------------------
        nfse_saved = 0
        nfse_days = max(1, int(CONTA_AZUL_SYNC_DAYS_BACK))
        cursor = today - timedelta(days=nfse_days)
        while cursor <= today and nfse_saved < CONTA_AZUL_SYNC_MAX_ITEMS:
            w_start = cursor
            w_end = min(today, cursor + timedelta(days=14))  # docs: range máximo 15 dias
            base_params = [
                ("tamanho_pagina", 100),
                ("data_competencia_de", w_start.isoformat()),
                ("data_competencia_ate", w_end.isoformat()),
            ]

            def _fetch_nfse_page(page_no: int, *, use_person: bool) -> list[dict[str, Any]]:
                params = [("pagina", page_no)] + base_params
                if use_person and person_id:
                    params.append(("id_cliente", person_id))
                payload = _contaazul_get_json(session, company_id, "/v1/notas-fiscais-servico", params=params)
                return (payload.get("itens") or []) if isinstance(payload, dict) else []

            page = 1
            window_items: list[dict[str, Any]] = []
            # primeiro tenta com person_id (se houver)
            if person_id:
                while nfse_saved < CONTA_AZUL_SYNC_MAX_ITEMS:
                    try:
                        itens = _fetch_nfse_page(page, use_person=True)
                    except Exception as e:
                        _ca_log(f"nfse fetch (person) failed {w_start}..{w_end}: {e}")
                        itens = []
                    if not itens:
                        break
                    window_items.extend([it for it in itens if isinstance(it, dict)])
                    if len(itens) < 100:
                        break
                    page += 1

            # por CNPJ/CPF (doc): o endpoint NÃO filtra por documento, então buscamos no período e filtramos localmente.
            # (garante que o vínculo seja sempre o documento, mesmo que person_id esteja errado/desatualizado)
            if doc:
                seen_ids = {str(it.get("id") or "") for it in window_items if isinstance(it, dict)}
                page = 1
                while nfse_saved < CONTA_AZUL_SYNC_MAX_ITEMS:
                    try:
                        itens = _fetch_nfse_page(page, use_person=False)
                    except Exception as e:
                        _ca_log(f"nfse fetch (doc filter) failed {w_start}..{w_end}: {e}")
                        break
                    if not itens:
                        break
                    for it in itens:
                        if not isinstance(it, dict):
                            continue
                        if _digits_only(str(it.get("documento_cliente") or "")) != doc:
                            continue
                        ext = str(it.get("id") or "")
                        if not ext or ext in seen_ids:
                            continue
                        window_items.append(it)
                        seen_ids.add(ext)
                    if len(itens) < 100:
                        break
                    page += 1

            if window_items:
                _ca_log(f"nfse window {w_start}..{w_end}: {len(window_items)} itens")
            for it in window_items:
                ext_id = str(it.get("id") or "")
                if not ext_id:
                    continue
                inv = session.exec(
                    select(ContaAzulInvoice).where(
                        ContaAzulInvoice.company_id == company_id,
                        ContaAzulInvoice.invoice_type == "NFSE",
                        ContaAzulInvoice.external_id == ext_id,
                    )
                ).first()
                if not inv:
                    inv = ContaAzulInvoice(company_id=company_id, client_id=client_id, invoice_type="NFSE",
                                           external_id=ext_id)

                inv.client_id = client_id
                inv.number = str(it.get("numero_nfse") or "")
                inv.issue_date = str(it.get("data_competencia") or "")
                inv.status = str(it.get("status") or "")
                inv.amount = float(it.get("valor_total_nfse") or 0.0)
                inv.raw_json = json.dumps(it, ensure_ascii=False)
                inv.updated_at = utcnow()
                session.add(inv)
                session.commit()
                nfse_saved += 1
                if nfse_saved >= CONTA_AZUL_SYNC_MAX_ITEMS:
                    break

            cursor = w_end + timedelta(days=1)

        # ----------------------------
        # Notas fiscais de produto (NF-e)
        # ----------------------------
        nfe_saved = 0
        if doc:
            cursor = today - timedelta(days=max(1, int(CONTA_AZUL_SYNC_DAYS_BACK)))
            while cursor <= today and (nfse_saved + nfe_saved) < CONTA_AZUL_SYNC_MAX_ITEMS:
                w_start = cursor
                w_end = min(today, cursor + timedelta(days=29))
                page = 1
                while (nfse_saved + nfe_saved) < CONTA_AZUL_SYNC_MAX_ITEMS:
                    params = {
                        "data_inicial": w_start.isoformat(),
                        "data_final": w_end.isoformat(),
                        "documento_tomador": doc,
                        "pagina": page,
                        "tamanho_pagina": 100,
                    }
                    try:
                        payload = _contaazul_get_json(session, company_id, "/v1/notas-fiscais", params=params)
                    except Exception as e:
                        _ca_log(f"nfe fetch failed {w_start}..{w_end}: {e}")
                        break

                    itens = (payload.get("itens") or []) if isinstance(payload, dict) else []
                    if not itens:
                        break

                    for it in itens:
                        if not isinstance(it, dict):
                            continue
                        chave = str(it.get("chave_acesso") or it.get("chave") or "").strip()
                        if not chave:
                            continue
                        inv = session.exec(
                            select(ContaAzulInvoice).where(
                                ContaAzulInvoice.company_id == company_id,
                                ContaAzulInvoice.invoice_type == "NFE",
                                ContaAzulInvoice.external_id == chave,
                            )
                        ).first()
                        if not inv:
                            inv = ContaAzulInvoice(company_id=company_id, client_id=client_id, invoice_type="NFE",
                                                   external_id=chave)
                        inv.client_id = client_id
                        inv.number = str(it.get("numero_nota") or it.get("numero") or "")
                        inv.issue_date = str(it.get("data_emissao") or "")
                        inv.status = str(it.get("status") or "")
                        inv.amount = 0.0
                        inv.raw_json = json.dumps(it, ensure_ascii=False)
                        inv.updated_at = utcnow()
                        session.add(inv)
                        session.commit()
                        nfe_saved += 1
                        if (nfse_saved + nfe_saved) >= CONTA_AZUL_SYNC_MAX_ITEMS:
                            break

                    if len(itens) < 100:
                        break
                    page += 1

                cursor = w_end + timedelta(days=1)

        _ca_log(f"sync done client_id={client_id}: nfse={nfse_saved} nfe={nfe_saved}")

        auth.last_sync_at = utcnow()
        _contaazul_save_auth(session, auth)


def get_session() -> Session:
    with Session(engine) as session:
        yield session


# ----------------------------
# Notion sync (optional)
# ----------------------------


async def sync_to_notion_negocios(*, user: User, company: Company, diagnostic: dict[str, Any]) -> None:
    if not (NOTION_TOKEN and NOTION_DB_NEGOCIOS_ID):
        return

    headers = {
        "Authorization": f"Bearer {NOTION_TOKEN}",
        "Notion-Version": "2022-06-28",
        "Content-Type": "application/json",
    }

    def rt(text: str) -> list[dict[str, Any]]:
        return [{"type": "text", "text": {"content": text}}]

    payload = {
        "parent": {"database_id": NOTION_DB_NEGOCIOS_ID},
        "properties": {
            "Nome": {"title": rt(user.name)},
            "Email": {"rich_text": rt(user.email)},
            "Empresa": {"rich_text": rt(company.name)},
            "Diagnóstico": {"rich_text": rt(json.dumps(diagnostic, ensure_ascii=False))},
            "Origem": {"rich_text": rt("App Escritório (Multi-tenant)")},
        },
    }

    try:
        async with httpx.AsyncClient(timeout=10) as client:
            resp = await client.post("https://api.notion.com/v1/pages", headers=headers, json=payload)
            resp.raise_for_status()
    except Exception:
        return


