def resolve_feature_key(path: str) -> Optional[str]:
    if path.startswith("/static/") or path.startswith("/login") or path.startswith("/logout"):
        return None
    if path.startswith("/api/"):
        return None
    if path in {"/", "/health"}:
        return None

    mapping = [
        ("/admin/ui", "ui"),
        ("/admin/financeiro", "financeiro_escritorio"),
        ("/admin/gestao", "gestao"),
        ("/admin/members", "gestao"),
        ("/admin/clients", "gestao"),
        ("/negocios", "crm"),
        ("/credito", "credito"),
        ("/empresa", "empresa"),
        ("/perfil", "perfil"),
        ("/financeiro", "financeiro"),
        ("/documentos", "documentos"),
        ("/consultoria", "consultoria"),
        ("/reunioes", "reunioes"),
        ("/tarefas", "tarefas"),
        ("/simulador", "simulador"),
        ("/propostas", "propostas"),
        ("/pendencias", "pendencias"),
        ("/agenda", "agenda"),
        ("/educacao", "educacao"),
        ("/ferramentas", "ferramentas"),
    ]
    for prefix, key in mapping:
        if path == prefix or path.startswith(prefix + "/"):
            return key
    return None


