@app.post("/admin/whatsapp/conversas/{thread_id}/mensagens")
@require_role({"admin", "equipe"})
async def whatsapp_thread_add_message(
    request: Request,
    thread_id: int,
    direction: str = Form(default="outbound"),
    body: str = Form(default=""),
    send_live: Optional[str] = Form(default=None),
    session: Session = Depends(get_session),
) -> Response:
    ctx = get_tenant_context(request, session)
    assert ctx is not None
    thread = session.get(WhatsAppThread, int(thread_id))
    if not thread or thread.company_id != ctx.company.id:
        set_flash(request, "Conversa não encontrada.")
        return RedirectResponse("/admin/whatsapp/caixa", status_code=303)
    clean_body = _clean_text(body, 5000)
    if not clean_body:
        set_flash(request, "Escreva uma mensagem.")
        return RedirectResponse(f"/admin/whatsapp/conversas/{thread.id}", status_code=303)

    delivery_status = "local"
    external_id = ""
    if direction == "outbound" and send_live:
        config = _get_or_create_whatsapp_config(session, company_id=ctx.company.id)
        ok, err, ext_id = await _try_send_whatsapp_text(config=config, to_phone=thread.contact_phone, body=clean_body)
        if ok:
            delivery_status = "sent"
            external_id = ext_id
        else:
            delivery_status = "failed"
            if err:
                set_flash(request, f"Mensagem registrada no app, mas não enviada via WhatsApp: {err}")

    msg = _whatsapp_add_message(
        session,
        thread=thread,
        direction=direction if direction in {"inbound", "outbound", "internal_note"} else "outbound",
        body=clean_body,
        sender_name=ctx.user.name,
        created_by_user_id=ctx.user.id,
        delivery_status=delivery_status,
        external_message_id=external_id,
    )
    chosen_topic = _whatsapp_menu_choice_to_topic(clean_body) if direction == "inbound" else None
    if chosen_topic:
        thread.topic_code = chosen_topic
        thread.assigned_user_id = thread.assigned_user_id or _whatsapp_pick_default_assignee(
            session, company_id=ctx.company.id, topic_code=chosen_topic
        )
        session.add(thread)
        session.commit()

    if direction == "inbound":
        _whatsapp_notify_new_inbound(session, thread=thread, preview=clean_body, created_by_user_id=ctx.user.id)

    return RedirectResponse(f"/admin/whatsapp/conversas/{thread.id}", status_code=303)


@app.get("/api/whatsapp/webhook")
async def whatsapp_webhook_verify(request: Request) -> Response:
    mode = request.query_params.get("hub.mode", "")
    token = request.query_params.get("hub.verify_token", "")
    challenge = request.query_params.get("hub.challenge", "")
    if mode == "subscribe" and WHATSAPP_VERIFY_TOKEN and token == WHATSAPP_VERIFY_TOKEN:
        return Response(content=challenge, media_type="text/plain")
    return Response(content="forbidden", status_code=403, media_type="text/plain")


def _extract_meta_whatsapp_messages(payload: dict[str, Any]) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    for entry in payload.get("entry") or []:
        if not isinstance(entry, dict):
            continue
        for change in entry.get("changes") or []:
            if not isinstance(change, dict):
                continue
            value = change.get("value") or {}
            if not isinstance(value, dict):
                continue
            metadata = value.get("metadata") or {}
            phone_number_id = str(metadata.get("phone_number_id") or "")
            contacts = value.get("contacts") or []
            contact_map: dict[str, str] = {}
            for c in contacts:
                if not isinstance(c, dict):
                    continue
                waid = str(c.get("wa_id") or "")
                profile = c.get("profile") or {}
                contact_map[waid] = str(profile.get("name") or "")
            for msg in value.get("messages") or []:
                if not isinstance(msg, dict):
                    continue
                wa_from = str(msg.get("from") or "")
                msg_type = str(msg.get("type") or "")
                body = ""
                if msg_type == "text":
                    body = str((msg.get("text") or {}).get("body") or "")
                elif msg_type == "button":
                    body = str((msg.get("button") or {}).get("text") or "")
                elif msg_type == "interactive":
                    interactive = msg.get("interactive") or {}
                    if "button_reply" in interactive:
                        body = str((interactive.get("button_reply") or {}).get("title") or "")
                    elif "list_reply" in interactive:
                        body = str((interactive.get("list_reply") or {}).get("title") or "")
                if not body:
                    body = f"[mensagem {msg_type or 'sem texto'}]"
                items.append({
                    "phone_number_id": phone_number_id,
                    "from": wa_from,
                    "profile_name": contact_map.get(wa_from, ""),
                    "body": body,
                    "message_id": str(msg.get("id") or ""),
                })
    return items


@app.post("/api/whatsapp/webhook")
async def whatsapp_webhook_receive(request: Request, session: Session = Depends(get_session)) -> JSONResponse:
    try:
        payload = await request.json()
    except Exception:
        payload = {}
    events = _extract_meta_whatsapp_messages(payload if isinstance(payload, dict) else {})
    processed = 0
    for event in events:
        phone_number_id = str(event.get("phone_number_id") or "")
        if not phone_number_id:
            continue
        config = session.exec(
            select(WhatsAppChannelConfig).where(
                WhatsAppChannelConfig.meta_phone_number_id == phone_number_id
            )
        ).first()
        if not config:
            continue
        company_id = int(config.company_id)
        incoming_phone = _only_digits(str(event.get("from") or ""))
        if not incoming_phone:
            continue
        thread = _whatsapp_find_open_thread_by_phone(session, company_id=company_id, phone_digits=incoming_phone)
        if not thread:
            matched_client = _match_client_by_phone(session, company_id=company_id, phone_digits=incoming_phone)
            thread = _whatsapp_create_thread(
                session,
                company_id=company_id,
                client_id=matched_client.id if matched_client else None,
                contact_name=str(event.get("profile_name") or "") or (matched_client.name if matched_client else ""),
                contact_phone=incoming_phone,
                is_group=False,
                group_name="",
                topic_code="geral",
                assigned_user_id=_whatsapp_pick_default_assignee(session, company_id=company_id, topic_code="geral"),
                status="aberto",
                source_kind="webhook",
                created_by_user_id=None,
            )
        body = str(event.get("body") or "")
        choice_topic = _whatsapp_menu_choice_to_topic(body)
        if choice_topic:
            thread.topic_code = choice_topic
            thread.assigned_user_id = thread.assigned_user_id or _whatsapp_pick_default_assignee(
                session, company_id=company_id, topic_code=choice_topic
            )
            session.add(thread)
            session.commit()
        _whatsapp_add_message(
            session,
            thread=thread,
            direction="inbound",
            body=body,
            sender_name=str(event.get("profile_name") or "") or "Cliente",
            created_by_user_id=None,
            delivery_status="received",
            external_message_id=str(event.get("message_id") or ""),
        )
        _whatsapp_notify_new_inbound(session, thread=thread, preview=body)
        processed += 1
    return JSONResponse({"ok": True, "processed": processed})



# =========================
# Safe layout/rules patch (retry)
# =========================

def _normalize_date_input(value: Any) -> str:
    s = (str(value or "")).strip()
    if not s:
        return ""
    for fmt in ("%d/%m/%Y", "%Y-%m-%d", "%d-%m-%Y", "%Y/%m/%d"):
        try:
            return datetime.strptime(s, fmt).strftime("%Y-%m-%d")
        except Exception:
            pass
    return s

def _format_date_br(value: Any) -> str:
    s = (str(value or "")).strip()
    if not s:
        return ""
    for fmt in ("%Y-%m-%d", "%d/%m/%Y", "%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S", "%Y-%m-%d %H:%M:%S.%f"):
        try:
            dt = datetime.strptime(s, fmt)
            if fmt != "%Y-%m-%d" and fmt != "%d/%m/%Y":
                dt = _to_brasilia_dt(dt.replace(tzinfo=timezone.utc))
            return dt.strftime("%d/%m/%Y")
        except Exception:
            pass
    try:
        if isinstance(value, datetime):
            try:
                return _to_brasilia_dt(value).strftime("%d/%m/%Y")
            except Exception:
                return value.strftime("%d/%m/%Y")
    except Exception:
        pass
    return s

BRASILIA_TZ = timezone(timedelta(hours=-3))


def _to_brasilia_dt(value: datetime) -> datetime:
    if value.tzinfo is None:
        value = value.replace(tzinfo=timezone.utc)
    return value.astimezone(BRASILIA_TZ)


def _format_dt_br(value: Any) -> str:
    if isinstance(value, datetime):
        try:
            return _to_brasilia_dt(value).strftime("%d/%m/%Y %H:%M")
        except Exception:
            return value.strftime("%d/%m/%Y %H:%M")
    s = (str(value or "")).strip()
    if not s:
        return ""
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%dT%H:%M:%S", "%Y-%m-%d %H:%M:%S.%f"):
        try:
            dt = datetime.strptime(s, fmt).replace(tzinfo=timezone.utc)
            return _to_brasilia_dt(dt).strftime("%d/%m/%Y %H:%M")
        except Exception:
            pass
    return s


def _meeting_meta(meeting: Meeting) -> dict[str, Any]:
    raw = {}
    try:
        raw = json.loads(meeting.raw_json or "{}")
        if not isinstance(raw, dict):
            raw = {}
    except Exception:
        raw = {}
    ext = raw.get("_app_meta")
    if not isinstance(ext, dict):
        ext = {}
        raw["_app_meta"] = ext

    meta = dict(ext)
    legacy_text = str(meta.get("annotation_text") or "").strip()
    legacy_visible = bool(meta.get("visible_to_client"))

    internal_text = str(meta.get("internal_annotation_text") or "").strip()
    client_text = str(meta.get("client_annotation_text") or "").strip()

    if legacy_text:
        if legacy_visible and not client_text:
            client_text = legacy_text
        elif not internal_text:
            internal_text = legacy_text

    meta["internal_annotation_text"] = internal_text
    meta["client_annotation_text"] = client_text
    meta["visible_to_client"] = bool(client_text)
    meta["total_hours"] = _meeting_hours_total(meta)
    return meta


def _meeting_meta_save(session: Session, meeting: Meeting, meta: dict[str, Any]) -> None:
    raw = {}
    try:
        raw = json.loads(meeting.raw_json or "{}")
        if not isinstance(raw, dict):
            raw = {}
    except Exception:
        raw = {}

    meta = dict(meta or {})
    meta["internal_annotation_text"] = str(meta.get("internal_annotation_text") or "").strip()
    meta["client_annotation_text"] = str(meta.get("client_annotation_text") or "").strip()
    meta["visible_to_client"] = bool(meta.get("client_annotation_text"))
    meta["total_hours"] = _meeting_hours_total(meta)

    if "annotation_text" in meta:
        meta.pop("annotation_text", None)

    raw["_app_meta"] = meta
    meeting.raw_json = json.dumps(raw, ensure_ascii=False)
    meeting.updated_at = utcnow()
    session.add(meeting)
    session.commit()


def _meeting_hours_total(meta: dict[str, Any]) -> float:
    started = meta.get("checked_in_at") or ""
    ended = meta.get("checked_out_at") or ""
    if not started or not ended:
        return float(meta.get("total_hours", 0.0) or 0.0)
    try:
        start_dt = datetime.fromisoformat(str(started))
        end_dt = datetime.fromisoformat(str(ended))
        delta_h = max(0.0, (end_dt - start_dt).total_seconds() / 3600.0)
        return round(delta_h, 2)
    except Exception:
        return float(meta.get("total_hours", 0.0) or 0.0)


def _meeting_client_hours_total(session: Session, company_id: int, client_id: int) -> float:
    total = 0.0
    rows = session.exec(
        select(Meeting).where(
            Meeting.company_id == int(company_id),
            Meeting.client_id == int(client_id),
        )
    ).all()
    for row in rows:
        total += _meeting_hours_total(_meeting_meta(row))
    return round(total, 2)


def _tool_admin_payload(

    session: Session,
    *,
    company_id: int,
    client_id: int,
    tool_code: str = CLIENT_TOOL_FINANCE_CODE,
) -> dict[str, Any]:
    sub = _get_or_create_client_tool_subscription(
        session,
        company_id=company_id,
        client_id=client_id,
        tool_code=tool_code,
    )
    pricing_mode = "free" if int(sub.monthly_price_credits or 0) <= 0 and sub.is_active else ("trial" if sub.status == "trial" or (sub.trial_ends_at and not sub.last_billed_period) else "paid")
    trial_days = 30
    if sub.trial_started_at and sub.trial_ends_at:
        try:
            trial_days = max(0, (sub.trial_ends_at.date() - sub.trial_started_at.date()).days)
        except Exception:
            trial_days = 30
    return {
        "is_active": bool(sub.is_active),
        "status": sub.status,
        "pricing_mode": pricing_mode,
        "trial_days": int(trial_days),
        "monthly_price_credits": int(sub.monthly_price_credits or CLIENT_TOOL_FINANCE_MONTHLY_CREDITS),
        "trial_started_at": sub.trial_started_at,
        "trial_ends_at": sub.trial_ends_at,
        "last_billed_period": sub.last_billed_period or "",
        "next_billing_at": sub.next_billing_at,
    }

# override helper: do not auto-start trial
def _get_or_create_client_tool_subscription(
    session: Session,
    *,
    company_id: int,
    client_id: int,
    tool_code: str = CLIENT_TOOL_FINANCE_CODE,
) -> ClientToolSubscription:
    row = session.exec(
        select(ClientToolSubscription).where(
            ClientToolSubscription.company_id == company_id,
            ClientToolSubscription.client_id == client_id,
            ClientToolSubscription.tool_code == tool_code,
        )
    ).first()
    if row:
        return row

    now = utcnow()
    row = ClientToolSubscription(
        company_id=company_id,
        client_id=client_id,
        tool_code=tool_code,
        status="blocked",
        trial_started_at=None,
        trial_ends_at=None,
        monthly_price_credits=CLIENT_TOOL_FINANCE_MONTHLY_CREDITS,
        next_billing_at=None,
        is_active=False,
        created_at=now,
        updated_at=now,
    )
    session.add(row)
    session.commit()
    session.refresh(row)
    return row

# override helper: respect manual release/trial/pricing
def _tool_subscription_status_payload(
    session: Session,
    *,
    company_id: int,
    client_id: int,
    tool_code: str = CLIENT_TOOL_FINANCE_CODE,
) -> dict[str, Any]:
    sub = _get_or_create_client_tool_subscription(
        session,
        company_id=company_id,
        client_id=client_id,
        tool_code=tool_code,
    )
    wallet = _get_or_create_wallet(session, company_id=company_id, client_id=client_id)

    now = utcnow()
    now_naive = now.replace(tzinfo=None) if getattr(now, "tzinfo", None) else now
    trial_ends = sub.trial_ends_at
    trial_ends_naive = trial_ends.replace(tzinfo=None) if trial_ends and getattr(trial_ends, "tzinfo", None) else trial_ends

    message = ""
    access_ok = False
    status_label = "Bloqueado"
    billed_this_month = sub.last_billed_period == _tool_period_label(now)

    if not sub.is_active or sub.status in {"blocked", "cancelled"}:
        message = "Ferramenta não liberada pela equipe."
        access_ok = False
        status_label = "Bloqueado"
    elif int(sub.monthly_price_credits or 0) <= 0 and sub.status == "active":
        message = "Ferramenta liberada sem cobrança."
        access_ok = True
        status_label = "Ativa"
    elif trial_ends_naive and now_naive < trial_ends_naive:
        sub.status = "trial"
        access_ok = True
        status_label = "Período grátis"
        days_left = max(0, (trial_ends_naive.date() - now_naive.date()).days)
        message = f"Período grátis ativo. Restam {days_left} dia(s)."
    else:
        if billed_this_month and sub.status == "active":
            access_ok = True
            status_label = "Ativa"
            message = f"Mensalidade do período {_tool_period_label(now)} já debitada."
        else:
            debit_ok = _wallet_debit_tool_fee(
                session,
                company_id=company_id,
                client_id=client_id,
                subscription_id=int(sub.id or 0),
                amount_credits=int(sub.monthly_price_credits or CLIENT_TOOL_FINANCE_MONTHLY_CREDITS),
                tool_code=tool_code,
            )
            if debit_ok:
                sub.status = "active"
                sub.last_billed_period = _tool_period_label(now)
                next_ref = (now_naive + timedelta(days=32)).replace(day=1)
                sub.next_billing_at = next_ref
                sub.updated_at = utcnow()
                session.add(sub)
                session.commit()
                access_ok = True
                status_label = "Ativa"
                message = f"Mensalidade de {int(sub.monthly_price_credits or 0)} créditos debitada para o período {sub.last_billed_period}."
                wallet = _get_or_create_wallet(session, company_id=company_id, client_id=client_id)
            else:
                sub.status = "blocked"
                sub.updated_at = utcnow()
                session.add(sub)
                session.commit()
                access_ok = False
                status_label = "Saldo insuficiente"
                message = f"Não foi possível debitar {int(sub.monthly_price_credits or 0)} créditos. Recarregue sua carteira."

    trial_active = bool(trial_ends_naive and now_naive < trial_ends_naive)

    return {
        "subscription": sub,
        "wallet": wallet,
        "access_ok": access_ok,
        "status_label": status_label,
        "message": message,
        "trial_active": trial_active,
        "trial_started_at": sub.trial_started_at,
        "trial_ends_at": sub.trial_ends_at,
        "monthly_price_credits": int(sub.monthly_price_credits or 0),
        "last_billed_period": sub.last_billed_period or "",
        "next_billing_at": sub.next_billing_at,
        "wallet_balance_credits": round(float(wallet.balance_cents or 0) / 100.0, 2),
    }

# simulator compat: accept rate_pct as well
def _loan_sim_inputs_from_form_safe(cls, **form) -> "LoanInput":
    chosen_rate = str(form.get("rate_pct") or form.get("rate") or "1,79")
    return build_loan_input(
        loan_type=form.get("loan_type", "Empréstimo"),
        amortization=form.get("amortization", "price"),
        rate_pct=chosen_rate,
        rate_base=form.get("rate_base", "am"),
        term_months=int(form.get("term_months", 24) or 24),
        principal=str(form.get("principal", "") or ""),
        collateral_value=str(form.get("collateral_value", "") or ""),
        ltv_pct=str(form.get("ltv_pct", "") or ""),
        start_date=form.get("start_date") or date.today(),
        grace_months=int(form.get("grace_months", 0) or 0),
        io_months=int(form.get("io_months", 0) or 0),
        fee_amount=str(form.get("fee_amount", "0") or "0"),
        monthly_insurance=str(form.get("monthly_insurance", "0") or "0"),
        monthly_admin_fee=str(form.get("monthly_admin_fee", "0") or "0"),
        borrower_name=str(form.get("borrower_name", "") or ""),
        notes=str(form.get("notes", "") or ""),
    )
LoanSimInputs.from_form = classmethod(_loan_sim_inputs_from_form_safe)

def _deal_lost_reason(deal: BusinessDeal) -> str:
    notes = deal.notes or ""
    m = re.search(r"\[LOST_REASON:(.*?)\]", notes, flags=re.IGNORECASE | re.DOTALL)
    return (m.group(1).strip() if m else "")

def _set_deal_lost_reason(notes: str, reason: str) -> str:
    base = re.sub(r"\s*\[LOST_REASON:.*?\]\s*", " ", notes or "", flags=re.IGNORECASE | re.DOTALL).strip()
    reason_clean = (reason or "").strip()
    return (base + (f"\n[LOST_REASON:{reason_clean}]" if reason_clean else "")).strip()

# Jinja filters/globals
try:
    templates_env.filters["brdate"] = _format_date_br
    templates_env.filters["brdatetime"] = _format_dt_br
    templates_env.globals["meeting_meta"] = _meeting_meta
    templates_env.globals["meeting_hours_total"] = _meeting_hours_total
    templates_env.globals["human_duration_minutes"] = _human_minutes_label
    templates_env.globals["human_duration_hours"] = _human_hours_label
    templates_env.globals["deal_lost_reason"] = _deal_lost_reason
except Exception:
    pass

